const Z_COLORS = {"-1.8":"#6a8caf","-0.5":"#7a9abf","0.0":"#8aa8cf","0.3":"#9ab6df","0.6":"#aac4ef","1.0":"#bacfee","1.5":"#caddff","1.8":"#ddeeff"};
const Z_OPAC = {"-1.8":0.9,"-0.5":0.7,"0.0":0.6,"0.3":0.5,"0.6":0.45,"1.0":0.4,"1.5":0.35,"1.8":0.3};
const Z_OPAC_REV = {"-1.8":0.3,"-0.5":0.4,"0.0":0.5,"0.3":0.5,"0.6":0.55,"1.0":0.6,"1.5":0.7,"1.8":0.9};

function toPath(pts, closed) {
  return pts.map((p,i) => `${i===0?"M":"L"}${p[0]},${-p[1]}`).join(" ") + (closed?" Z":"");
}

function PieceView({piece, title, scale=6, viewMode="top", w=400, h=400}) {
  const b = piece.b;
  const pad = 2;
  const hw = b[0]/2 + pad, hh = b[1]/2 + pad;
  const vb = `${-hw} ${-hh} ${hw*2} ${hh*2}`;
  const opMap = viewMode === "bottom" ? Z_OPAC : Z_OPAC_REV;
  const zOrder = viewMode === "bottom"
    ? ["-1.8","-0.5","0.6","1.8"]
    : ["1.8","0.6","-0.5","-1.8"];

  return (
    <div style={{background:"#1a1a22",borderRadius:8,padding:12,border:"1px solid #2a2a34"}}>
      <div style={{fontSize:11,color:"#8a8890",marginBottom:6,letterSpacing:0.5}}>{title}</div>
      <svg width={w} height={h} viewBox={vb} style={{display:"block",margin:"0 auto",background:"#0e0e14",borderRadius:4}}>
        {/* Grid */}
        <rect x={-b[0]/2} y={-b[1]/2} width={b[0]} height={b[1]} fill="none" stroke="#333" strokeWidth={0.08} strokeDasharray="0.3 0.3"/>
        {zOrder.map(zk => {
          const contours = piece.layers[zk];
          if (!contours) return null;
          const op = opMap[zk] || 0.5;
          const col = Z_COLORS[zk] || "#aaa";
          return (
            <g key={zk} opacity={op}>
              {contours.map((c, i) => (
                <path key={i} d={toPath(c.p, c.c)}
                  fill={c.c ? col+"18" : "none"}
                  stroke={col} strokeWidth={0.12} strokeLinejoin="round"/>
              ))}
            </g>
          );
        })}
      </svg>
    </div>
  );
}

function XSecView({xsec, title}) {
  const pad = 1;
  const vb = `${-28-pad} ${-2-pad-1} ${56+pad*2} ${4+pad*2+2}`;
  const colors = {"0.0":"#e85d26","10.0":"#d94a90","21.0":"#4a90d9"};
  return (
    <div style={{background:"#1a1a22",borderRadius:8,padding:12,border:"1px solid #2a2a34"}}>
      <div style={{fontSize:11,color:"#8a8890",marginBottom:6}}>{title}</div>
      <svg width={560} height={180} viewBox={vb} style={{display:"block",margin:"0 auto",background:"#0e0e14",borderRadius:4}}>
        <g transform="scale(1,-1)">
          <line x1={-28} y1={0} x2={28} y2={0} stroke="#333" strokeWidth={0.03}/>
          <rect x={-27.5} y={-2} width={55} height={4} fill="none" stroke="#444" strokeWidth={0.04} strokeDasharray="0.3 0.3"/>
          {Object.entries(xsec).map(([yk, contours]) => (
            <g key={yk}>
              {contours.map((c,i) => (
                <path key={i} d={toPath(c.p.map(p=>[p[0],-p[1]]),c.c)}
                  fill={c.c ? (colors[yk]||"#aaa")+"25" : "none"}
                  stroke={colors[yk]||"#aaa"} strokeWidth={0.06} strokeLinejoin="round"/>
              ))}
            </g>
          ))}
        </g>
      </svg>
      <div style={{display:"flex",gap:12,marginTop:6,justifyContent:"center"}}>
        {Object.entries(colors).map(([k,c])=>(
          <div key={k} style={{fontSize:10,color:c,display:"flex",alignItems:"center",gap:4}}>
            <div style={{width:8,height:8,background:c,borderRadius:1}}/> Y={k}
          </div>
        ))}
      </div>
    </div>
  );
}

export default function Viewer() {
  const [mode, setMode] = useState("top");
  return (
    <div style={{minHeight:"100vh",background:"#0a0a0f",color:"#e0ded9",fontFamily:"'JetBrains Mono',monospace",padding:20}}>
      <div style={{maxWidth:900,margin:"0 auto"}}>
        <h1 style={{fontSize:20,fontWeight:700,color:"#e85d26",margin:"0 0 4px"}}>ClickFinity Geometry</h1>
        <p style={{fontSize:11,color:"#6a6876",margin:"0 0 16px"}}>
          Contours extracted from official 3MF at 4 Z-levels. Each layer rendered with depth-based opacity.
        </p>
        <div style={{display:"flex",gap:4,marginBottom:16}}>
          {[["top","Top View"],["bottom","Bottom View"],["xsec","Cross-Section"]].map(([id,l])=>(
            <button key={id} onClick={()=>setMode(id)} style={{
              padding:"6px 14px",fontSize:10,fontFamily:"inherit",letterSpacing:0.8,
              textTransform:"uppercase",cursor:"pointer",borderRadius:5,
              color:mode===id?"#e85d26":"#6a6876",
              background:mode===id?"#e85d2618":"transparent",
              border:`1px solid ${mode===id?"#e85d2644":"#2a2a34"}`,
            }}>{l}</button>
          ))}
        </div>
        {mode !== "xsec" ? (
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
            <PieceView piece={D.grid_1x1} title={`1×1 Grid (55×55mm) — ${mode} view`} viewMode={mode} w={380} h={380}/>
            <div style={{display:"grid",gridTemplateRows:"1fr 1fr",gap:12}}>
              <PieceView piece={D.hub} title={`Hub (13×13mm) — ${mode} view`} viewMode={mode} w={380} h={180}/>
              <PieceView piece={D.joiner} title={`Joiner (6.6×33.8mm) — ${mode} view`} viewMode={mode} w={380} h={180}/>
            </div>
          </div>
        ) : (
          <XSecView xsec={D.grid_1x1.xsec} title="1×1 Grid Cross-Sections (X-Z plane at Y=0, 10, 21mm)"/>
        )}
        <div style={{display:"flex",gap:8,marginTop:12,flexWrap:"wrap",justifyContent:"center"}}>
          {Object.entries(Z_COLORS).map(([z,c])=>(
            <div key={z} style={{fontSize:9,color:"#6a6876",display:"flex",alignItems:"center",gap:3}}>
              <div style={{width:8,height:8,background:c,borderRadius:1,opacity:0.8}}/> Z={z}mm
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
